const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Client } = require('pg');

const schema = buildSchema(`
  type Query {
    posts: [Post]
  }

  type Post {
    id: String
    title: String
    author: Author
  }

  type Author {
    id: String
    name: String
  }

`);

const root = {
  posts: async () => {
    const client = new Client({
      connectionString: 'postgresql://user:password@localhost/database'
    });
    await client.connect();
    const res = await client.query('SELECT * FROM posts');

    return res.rows.map(async (post) => ({
      id: post.id,
      title: post.title,
      author: (async () => {
        const result = await client.query('SELECT * FROM authors WHERE id = $1', [post.author_id]);
        client.end();
        return result.rows[0];
      })(),
    }));
  },
};

const app = express();
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: true,
}));

app.listen(4000);
console.log('Running a GraphQL API server at http://localhost:4000/graphql');